+        points2.at<cv::Vec2f>(0, i)[0] * 16.0),
+        cvRound(points2.at<cv::Vec2f>(0, i)[1] * 16.0));
+      circle(draw_image, center1, 48, color1, 1, CV_AA, 4);
+      line(draw_image, center1, center2, color2, 1, CV_AA, 4);
