+  bool PitchAndRollEstimator::EstimateTransforms(
+      cv::Mat& pts1,
+      cv::Mat& pts2,
+      cv::Mat& T_affine,
+      cv::Mat& T_rigid,
+      double& rms_error)
+  {
+    cv::Mat inliers1;
+    cv::Mat inliers2;
+    T_affine = ComputeLooseAffine2DTransform(
+        pts1, pts2, inliers1, inliers2, T_rigid, rms_error);
+
+    if (T_affine.empty())
+    {
+      return false;
+    }
+
+    return true;
