+      // Check to see whether the rotation matrix is close to valid
+      // TODO(kkozak): Parameterize this
+      if (fabs(cn - 1.0) > .1 || rnorm > maxRNorm)
+      {
+        // ROS_ERROR("Did not meet condition number or rnorm criteria: cn = %f,
+        // rnorm = %g",cn,rnorm);
