+TEST(GeometryUtilTests, Intersects)
+{
+  image_util::BoundingBox b1(-2, -2, 4, 4);
+  image_util::BoundingBox b2(-1, -1, 2, 2);
+  image_util::BoundingBox b3(-4, -4, 2.5, 2.5);
