+  EXPECT_NEAR(transform.at<float>(2,1), estimated.at<float>(2,1), .008);
+  EXPECT_NEAR(transform.at<float>(2,2), estimated.at<float>(2,2), .008);
+  EXPECT_NEAR(transform.at<float>(2,3), estimated.at<float>(2,3), .25);
+}
