+        cv::Vec3f& A_i = A.at<cv::Vec3f>(i, 0);
+        A_i[0] = point[0];
+        A_i[1] = point[1];
+        A_i[2] = 1.0;
+      }
+    }
+    
+    cv::Mat x;
+    if (cv::solve(A, B, x))
+    {
+      transform = x;
+    }
+
+    return transform;
+  }
+}

