+  {
+    if (target_frame == _utm_frame)
+    {
+      if (source_frame == _wgs84_frame)
+      {
+        transform = boost::make_shared<Wgs84ToUtmTransform>(utm_util_);
+
+        return true;
+      }
+      else
+      {
+        if (!initialized_)
+        {
+          Initialize();
