+    else if (target_frame == _wgs84_frame && source_frame == _utm_frame)
+    {
+      if (!initialized_)
+      {
+        Initialize();
+      }
+
+      if (initialized_)
+      {
+        transform = boost::make_shared<UtmToWgs84Transform>(
+                utm_util_,
+                utm_zone_,
+                utm_band_);
+
+        return true;
+      }
+    }
+    else if (source_frame == _utm_frame)
+    {
+      if (!initialized_)
+      {
