+    double dy = ((double)std::rand() / RAND_MAX) * math_util::_half_pi * .5 - math_util::_half_pi * .25;
+    double dp = ((double)std::rand() / RAND_MAX) * math_util::_half_pi * .5 - math_util::_half_pi * .25;
