+
+    tf::Quaternion q2;
+    q2.setRPY(r + dr, p + dp, y + dy);
+
+
+    EXPECT_NEAR(0, q1.angleShortestPath(transform_util::SnapToRightAngle(q1)), 0.00000003);
+    EXPECT_NEAR(0, q1.angleShortestPath(transform_util::SnapToRightAngle(q2)), 0.00000003);
